class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        unordered_map<char, int> charValues;
        for (int i = 0; i < chars.size(); ++i) {
            charValues[chars[i]] = vals[i];
        }

        int maxCost = 0;
        int currentCost = 0;
        for (char c : s) {
            int value = charValues.find(c) != charValues.end() ? charValues[c] : c - 'a' + 1;
            currentCost = max(value, currentCost + value);
            maxCost = max(maxCost, currentCost);
        }
        return maxCost;
    }
};
